  const fetchNews = async () => {
      if (!isAIConfigured()) return;
      setLoadingNews(true);
      const liveNews = await getLiveGoldNews();
      setNews(liveNews);
      setLoadingNews(false);
      setLastUpdated(new Date());
  };

  // Fetch Data when Range Changes
